"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[9397],{7947(e,o,t){t.r(o),t.d(o,{assets:()=>h,contentTitle:()=>r,default:()=>u,frontMatter:()=>n,metadata:()=>s,toc:()=>d});const s=JSON.parse('{"id":"stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-19","title":"Discourses \u2014 Book 1, Chapter 19","description":"Book 1 \u2014 Chapter 19","source":"@site/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-19.md","sourceDirName":"stoicism/epictetus/discourses/book-1","slug":"/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-19","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-19","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":19,"frontMatter":{"sidebar_position":19,"title":"Discourses \u2014 Book 1, Chapter 19","sidebar_label":"Book 1, Ch. 19"},"sidebar":"philosophersSidebar","previous":{"title":"Book 1, Ch. 18","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-18"},"next":{"title":"Book 1, Ch. 20","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-20"}}');var a=t(4848),i=t(8453);const n={sidebar_position:19,title:"Discourses \u2014 Book 1, Chapter 19",sidebar_label:"Book 1, Ch. 19"},r="Discourses",h={},d=[{value:"Book 1 \u2014 Chapter 19",id:"book-1--chapter-19",level:2},{value:"How One Should Behave Towards Tyrants",id:"how-one-should-behave-towards-tyrants",level:3},{value:"Text",id:"text",level:2}];function l(e){const o={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,i.R)(),...e.components},{Details:t}=o;return t||function(e,o){throw new Error("Expected "+(o?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,a.jsxs)(a.Fragment,{children:[(0,a.jsxs)("div",{style:{textAlign:"center"},children:[(0,a.jsx)(o.header,{children:(0,a.jsx)(o.h1,{id:"discourses",children:"Discourses"})}),(0,a.jsx)(o.h2,{id:"book-1--chapter-19",children:"Book 1 \u2014 Chapter 19"}),(0,a.jsx)(o.h3,{id:"how-one-should-behave-towards-tyrants",children:"How One Should Behave Towards Tyrants"})]}),"\n",(0,a.jsx)(o.p,{children:(0,a.jsx)(o.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,a.jsxs)(t,{open:!0,children:[(0,a.jsx)("summary",{children:"Text"}),(0,a.jsx)(o.h2,{id:"text",children:"Text"}),(0,a.jsx)(o.p,{children:"IF A man possesses some advantage, or thinks he does though he does not, he is bound, if he be uneducated, to be puffed up because of it. The tyrant, for instance, says, 'I am mightiest of all men.'"}),(0,a.jsx)(o.p,{children:"Well, and what can you give me? Can you enable me to get what I will to get? How can you? Can you avoid what you will to avoid, independent of circumstances? Is your impulse free from error? How can you claim any such power?"}),(0,a.jsx)(o.p,{children:"Tell me, on shipboard, do you put confidence in yourself or in the man who knows? And in a chariot? Surely in him who knows. How is it in other arts? Exactly the same. What does your power come to then?"}),(0,a.jsx)(o.p,{children:"'All men pay me attention.'"}),(0,a.jsx)(o.p,{children:"Yes, and I pay attention to my platter and work it and polish it and I fix up a peg for my oil-flask. Does that mean that these are superior to me? No, but they do me some service, and for this reason I pay them attention. Again: do I not pay attention to my ass? Do I not wash his feet? Do I not curry him? Do you not know that every man pays regard to himself, and to you only as to his ass? For who pays regard to you as a man? Show me. Who wishes to become like you? Who regards you as one like Socrates to admire and follow?"}),(0,a.jsx)(o.p,{children:"'But I can behead you.'"}),(0,a.jsx)(o.p,{children:"Well said. I forgot, of course, one ought to pay you worship as if you were fever or cholera, and raise an altar to you, like the altar to Fever in Rome."}),(0,a.jsx)(o.p,{children:"What is it then which disturbs and confounds the multitude? Is it the tyrant and his guards? Nay, God forbid! It is impossible for that which is free by nature to be disturbed or hindered by anything but itself. It is a man's own judgements which disturb him. For when the tyrant says to a man, 'I will chain your leg,' he that values his leg says, 'Nay, have mercy,' but he that values his will says, 'If it seems more profitable to you, chain it.'"}),(0,a.jsx)(o.p,{children:"'Do you pay no heed?'"}),(0,a.jsx)(o.p,{children:"No, I pay no heed."}),(0,a.jsx)(o.p,{children:"'I will show you that I am master.'"}),(0,a.jsx)(o.p,{children:"How can you? Zeus gave me my freedom. Or do you think that he was likely to let his own son be enslaved? You are master of my dead body, take it."}),(0,a.jsx)(o.p,{children:"'Do you mean that when you approach me, you pay no respect to me?' No, I only pay respect to myself: if you wish me to say that I pay respect to you too, I tell you that I do so, but only as I pay respect to my water-pot."}),(0,a.jsx)(o.p,{children:"This is not mere self-love: for it is natural to man, as to other creatures, to do everything for his own sake; for even the sun does everything for its own sake, and in a word so does Zeus himself. But when he would be called 'The Rain-giver' and 'Fruit-giver' and 'Father of men and gods', you see that he cannot win these names or do these works"}),(0,a.jsx)(o.p,{children:"unless he does some good to the world at large: and in general he has so created the nature of the rational animal, that he can attain nothing good for himself, unless he contributes some service to the community. So it turns out that to do everything for his own sake is not unsocial. For what do you expect? Do you expect a man to hold aloof from himself and his own interest? No: we cannot ignore the one principle of action which governs all things--to be at unity with themselves."}),(0,a.jsx)(o.p,{children:"What follows? When men's minds harbour wrong opinions on things beyond the will, counting them good and evil, they are bound to pay regard to tyrants. Would that it were only tyrants, and not chamberlains too! How can a man possibly grow wise of a sudden, when Caesar appoints him to the charge of the privy? How is it we straightway say, 'Felicio has spoken wisely to me'? I would fain have him deposed from the dung-heap, that he may seem foolish to you again. Epaphroditus had a shoemaker, whom he sold because he was useless: then by some chance he was bought by one of Caesar's officials, and became Caesar's shoemaker. If you could have seen how Epaphroditus honoured him. 'How is my good Felicio, I pray you?' Then if some one asked us, 'What is your master doing?' the answer was, 'He is consulting Felicio about something.' What, had he not sold him for useless? Who has suddenly made a wise man of him? This is what comes of honouring anything outside one's will."}),(0,a.jsx)(o.p,{children:"He has been honoured with a tribuneship. All who meet him congratulate him; one kisses his eyes, another his neck, his slaves kiss his hands. He comes into his house and finds lamps being lighted. He goes up to the Capitol and offers sacrifice. Who, I ask you, ever offered sacrifice in gratitude for right direction of the will or for impulse in accordance with nature? For we give thanks to the gods for what we think our good!"}),(0,a.jsx)(o.p,{children:"To-day one spoke to me about the priesthood of Augustus. I told him, 'Fellow, leave the thing alone; you will spend a great deal on nothing.'"}),(0,a.jsx)(o.p,{children:"'Well, but those who draw up contracts will record my name.'"}),(0,a.jsx)(o.p,{children:"Can you be there when men read it and say to them, 'That is my name,' and even supposing you can be there now, what will you do if you die?"}),(0,a.jsx)(o.p,{children:"'My name will remain.'"}),(0,a.jsx)(o.p,{children:"Write it on a stone and it will remain. But who will remember you outside Nicopolis?"}),(0,a.jsx)(o.p,{children:"'But I shall wear a golden crown.'"}),(0,a.jsx)(o.p,{children:"If you desire a crown at all, take a crown of roses and wear that: you will look smarter in that."})]})]})}function u(e={}){const{wrapper:o}={...(0,i.R)(),...e.components};return o?(0,a.jsx)(o,{...e,children:(0,a.jsx)(l,{...e})}):l(e)}},8453(e,o,t){t.d(o,{R:()=>n,x:()=>r});var s=t(6540);const a={},i=s.createContext(a);function n(e){const o=s.useContext(i);return s.useMemo(function(){return"function"==typeof e?e(o):{...o,...e}},[o,e])}function r(e){let o;return o=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:n(e.components),s.createElement(i.Provider,{value:o},e.children)}}}]);